#ifdef BLOCK_SIZE
#define BS BLOCK_SIZE
#else
#define BS 16
#endif

kernel void lud_diagonal(global float* a, local float* temp, const int size, const int offset)
{
    int i, j, k;

    for (i = 0; i < BS; i++) {
        for (j = i; j < BS; j++) {
            for (k = 0; k < i; k++) {
                a[(offset+i)*size + offset+j] -= a[(offset+i)*size + offset+k] * a[(offset+k)*size + offset+j];
            }
        }

        float temp_val = 1.0f / a[(offset+i)*size + offset+i];
        for (j = i+1; j < BS; j++) {
            for (k = 0; k < i; k++) {
                a[(offset+j)*size + offset+i] -= a[(offset+j)*size + offset+k] * a[(offset+k)*size + offset+i];
            }
            a[(offset+j)*size + offset+i] *= temp_val;
        }
    }
}

kernel void lud_perimeter(global float* a, local float* temp1, local float* temp2, local float* temp3, 
                          const int size, const int offset)
{
    int item_1 = get_global_id(0);
    int chunks_per_row = (size - offset - BS) / BS;
    int total_chunks = chunks_per_row;

    if (item_1 >= chunks_per_row * 2) return;

    int i, j, k;
    float sum;

    if (item_1 < chunks_per_row) {
        // Right perimeter (update rows below diagonal block)
        int var_4 = offset;
        int item_7 = offset + BS * (item_1 + 1);

        for (j = 0; j < BS; j++) {
            for (i = 0; i < BS; i++) {
                sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += a[(offset+i)*size + offset+k] * a[(var_4+k)*size + item_7+j];
                }
                a[(var_4+i)*size + item_7+j] -= sum;
            }
        }
    } else {
        // Bottom perimeter (update columns right of diagonal block)
        int item_1_bottom = item_1 - chunks_per_row;
        int var_4 = offset + BS * (item_1_bottom + 1);
        int item_7 = offset;

        for (i = 0; i < BS; i++) {
            for (j = 0; j < BS; j++) {
                sum = 0.0f;
                for (k = 0; k < j; k++) {
                    sum += a[(var_4+i)*size + item_7+k] * a[(offset+k)*size + offset+j];
                }
                a[(var_4+i)*size + item_7+j] = (a[(var_4+i)*size + item_7+j] - sum) / a[(offset+j)*size + offset+j];
            }
        }
    }
}

kernel void lud_internal(global float* a, local float* temp_top, local float* temp_bottom, 
                         const int size, const int offset)
{
    int chunk_idx = get_global_id(0);
    int chunk_idy = get_global_id(1);
    int chunks_per_row = (size - offset - BS) / BS;

    if (chunk_idx >= chunks_per_row || chunk_idy >= chunks_per_row) return;

    int i, j, k;
    float sum;

    int v_8 = offset + BS * (1 + chunk_idx);
    int data_3 = offset + BS * (1 + chunk_idy);

    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            sum = 0.0f;
            for (k = 0; k < BS; k++) {
                sum += a[(offset+i)*size + data_3+k] * a[(v_8+k)*size + offset+j];
            }
            a[(v_8+i)*size + data_3+j] -= sum;
        }
    }
}
